import java.util.Scanner;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Use a dynamically sized StringBuilder instead of a fixed-size array
        StringBuilder buffer = new StringBuilder();

        // Copying the user input into the StringBuilder
        for (int i = 0; i < name.length(); i++) {
            if (buffer.length() < 10) { // Ensure buffer size limit
                buffer.append(name.charAt(i));
            } else {
                break; // Exit loop if buffer size limit reached
            }
        }

        System.out.println("Hello, " + buffer.toString());
    }
}

